interface Service { fetch(): Promise<string>; }

class RealService implements Service {
  async fetch() { /* network call */ return 'data'; }
}

class CachingWrapper implements Service {
  private cache?: string;
  constructor(private real: Service) {}
  async fetch() {
    if (this.cache) return this.cache; // short-circuit
    this.cache = await this.real.fetch();
    return this.cache;
  }
}

class LoggingWrapper implements Service {
  constructor(private real: Service) {}
  async fetch() {
    console.log('fetch start');
    const r = await this.real.fetch();
    console.log('fetch end');
    return r;
  }
}

