class LazyDBClient implements DB {
  private real?: RealDB;
  constructor(private user: User) {}
  private ensure() {
    if (!this.real) {
      if (!Auth.allow(this.user)) throw new Error('access denied');
      this.real = new RealDB(); // expensive connect here
    }
  }
  async query(sql: string) { this.ensure(); return this.real!.query(sql); }
}

